mapper.update:
UPDATE club_manages
SET    CLUB_TITLE  = #{clubTitle},
       LOCATION    = #{location},
       MAX_MEMBERS = #{maxMembers},
       DESCRIPTION = #{description}
WHERE  CLUB_ID     = #{clubId}

UPDATE club_members
SET    BIRTH_YEAR  = #{birthYear},
       GENDER      = #{gender},
       ADDR1LEVEL  = #{addr1Level},
       ADDR2LEVEL  = #{addr2Level},
       ADDR3LEVEL  = #{addr3Level}
WHERE  CLUB_ID = #{clubId}
  AND  USER_ID = #{userId}

UPDATE club_members
SET    STATUS = 'N'
WHERE  MEMBER_SEQ = #{memberSeq}

mapper.select:
SELECT COUNT(*)
FROM   club_members
WHERE  USER_ID = #{userId}
  AND  CLUB_ID = #{clubId}
  AND  STATUS  = 'Y'

SELECT USER_ID   AS userId,
       USER_NAME AS userName
FROM   join_user
WHERE  USER_ID   LIKE #{keyword}
   OR  USER_NAME LIKE #{keyword}
LIMIT  10
